        bool won = (block.number % 2) == 0;

        bets.push(Bet(msg.value, block.number, won));

        if (won) {
            if (!msg.sender.send(msg.value)) {
                throw;
            }
        }
    }

    function getBets() {
        if (msg.sender != organizer) {
            throw;
        }

        for (uint i = 0; i < bets.length; i++) {
            GetBet(bets[i].betAmount, bets[i].blockNumber, bets[i].won);
        }
    }

    function destroy() {
        if (msg.sender != organizer) {
            throw;
        }

        suicide(organizer);
    }
}
